   168  func RulesAllow(requestAttributes authorizer.Attributes, rules ...rbacv1.PolicyRule) bool {
   169          for i := range rules {
   170                  if RuleAllows(requestAttributes, &rules[i]) {
   171                          return true
   172                  }
   173          }
   174
   175          return false
   176  }
